// Compliant: Extract common logic into interface and shared function
type Entity interface {
    GetEmail() string
    GetName() string
    SetUpdatedAt(time.Time)
    Save() error
}

func ProcessEntity(entity Entity) error {
    if entity.GetEmail() == "" {
        return errors.New("email required")
    }
    if entity.GetName() == "" {
        return errors.New("name required")
    }
    entity.SetUpdatedAt(time.Now())
    return entity.Save()
}

// Specific implementations only handle their unique logic
func ProcessUser(user User) error {
    // User-specific validation if needed
    return ProcessEntity(user)
}

func ProcessAdmin(admin Admin) error {
    // Admin-specific validation
    if !admin.HasPermission() {
        return errors.New("insufficient permissions")
    }
    return ProcessEntity(admin)
}

// Alternative: Use generics (Go 1.18+)
func ProcessData[T Entity](entity T) error {
    if entity.GetEmail() == "" {
        return errors.New("email required")
    }
    if entity.GetName() == "" {
        return errors.New("name required")
    }
    entity.SetUpdatedAt(time.Now())
    return entity.Save()
}
